  // Process each row to check if it consists of even numbers only
  for i := n-1 downto 0 do
  begin
    row := arr[i];
    if IsRowEven(row) then
      writeln(Join(row, ' '))
  end;
end.

function IsRowEven(row: array of integer): boolean;
var
  j: integer;
begin
  for j := Low(row) to High(row) do
    if Odd(row[j]) then
    begin
      Result := false;
      Exit;
    end;
  Result := true;
end;

function Join(items: array of integer; const delimiter: string): string;
var
  j: integer;
begin
  Result := '';
  for j := Low(items) to High(items) do
  begin
    if j > Low(items) then
      Result := Result + delimiter;
    Result := Result + IntToStr(items[j]);
  end;
end.
